import{_ as a,o as s,c as n,ag as t}from"./chunks/framework.BDReElpY.js";const g=JSON.parse('{"title":"Literals","description":"","frontmatter":{},"headers":[],"relativePath":"archive/extra/archive/Baseline/01_literals.md","filePath":"archive/extra/archive/Baseline/01_literals.md"}'),i={name:"archive/extra/archive/Baseline/01_literals.md"};function l(o,e,p,r,c,d){return s(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="literals" tabindex="-1">Literals <a class="header-anchor" href="#literals" aria-label="Permalink to &quot;Literals&quot;">​</a></h1><p><strong>Baseline Feature</strong><br><strong>Version:</strong> 0.2.0<br><strong>Status:</strong> ✅ Implemented<br><strong>Test:</strong> <code>00_base_feats/01_literals.vx</code></p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Literals are fixed values written directly in source code. Vex supports integer, floating-point, boolean, string, and byte literals.</p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>All literals in Vex are strictly typed. While the compiler can infer types (e.g., <code>42</code> is <code>i32</code>), explicit suffixes allow you to specify the exact type (e.g., <code>42u8</code>).</p></div><h2 id="integer-literals" tabindex="-1">Integer Literals <a class="header-anchor" href="#integer-literals" aria-label="Permalink to &quot;Integer Literals&quot;">​</a></h2><h3 id="decimal-integers" tabindex="-1">Decimal Integers <a class="header-anchor" href="#decimal-integers" aria-label="Permalink to &quot;Decimal Integers&quot;">​</a></h3><p>Basic decimal numbers without prefix.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let zero = 0;</span></span>
<span class="line"><span>let answer = 42;</span></span>
<span class="line"><span>let max_u8 = 255;</span></span></code></pre></div><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>Visual separators (underscores like <code>1_000</code>) are <strong>not yet supported</strong> in the Lexer. Please write numbers continuously: <code>1000000</code>.</p></div><p><strong>Default Type:</strong> <code>i32</code><br><strong>Regex:</strong> <code>[0-9]+</code></p><h3 id="hexadecimal-integers" tabindex="-1">Hexadecimal Integers <a class="header-anchor" href="#hexadecimal-integers" aria-label="Permalink to &quot;Hexadecimal Integers&quot;">​</a></h3><p>Prefix: <code>0x</code> or <code>0X</code></p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let color = 0xFF;           // 255</span></span>
<span class="line"><span>let flags = 0x1A2B;         // 6699</span></span></code></pre></div><p><strong>Regex:</strong> <code>0[xX][0-9a-fA-F]+</code></p><h3 id="binary-integers" tabindex="-1">Binary Integers <a class="header-anchor" href="#binary-integers" aria-label="Permalink to &quot;Binary Integers&quot;">​</a></h3><p>Prefix: <code>0b</code> or <code>0B</code></p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let bits = 0b1010;          // 10</span></span>
<span class="line"><span>let mask = 0b11110000;      // 240</span></span></code></pre></div><p><strong>Regex:</strong> <code>0[bB][01]+</code></p><h3 id="octal-integers" tabindex="-1">Octal Integers <a class="header-anchor" href="#octal-integers" aria-label="Permalink to &quot;Octal Integers&quot;">​</a></h3><p>Prefix: <code>0o</code> or <code>0O</code></p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let permissions = 0o755;    // 493</span></span></code></pre></div><p><strong>Regex:</strong> <code>0[oO][0-7]+</code></p><h3 id="explicit-type-suffixes" tabindex="-1">Explicit Type Suffixes <a class="header-anchor" href="#explicit-type-suffixes" aria-label="Permalink to &quot;Explicit Type Suffixes&quot;">​</a></h3><p>You can force a literal to be a specific type by appending the type name.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let small = 127i8;          // Type is i8</span></span>
<span class="line"><span>let unsigned = 100u32;      // Type is u32</span></span>
<span class="line"><span>let big = 1000000i64;       // Type is i64</span></span>
<span class="line"><span>let byte_hex = 0xFFu8;      // Type is u8</span></span></code></pre></div><h2 id="floating-point-literals" tabindex="-1">Floating-Point Literals <a class="header-anchor" href="#floating-point-literals" aria-label="Permalink to &quot;Floating-Point Literals&quot;">​</a></h2><h3 id="basic-floats" tabindex="-1">Basic Floats <a class="header-anchor" href="#basic-floats" aria-label="Permalink to &quot;Basic Floats&quot;">​</a></h3><p>Decimal numbers with a decimal point.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let pi = 3.14;</span></span>
<span class="line"><span>let half = 0.5;</span></span></code></pre></div><p><strong>Default Type:</strong> <code>f64</code> (Double precision)<br><strong>Regex:</strong> <code>[0-9]+\\.[0-9]+</code></p><h3 id="scientific-notation" tabindex="-1">Scientific Notation <a class="header-anchor" href="#scientific-notation" aria-label="Permalink to &quot;Scientific Notation&quot;">​</a></h3><p>Exponential format with <code>e</code> or <code>E</code>.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let large = 1.5e10;         // 15000000000.0</span></span>
<span class="line"><span>let tiny = 2.0e-5;          // 0.00002</span></span></code></pre></div><h2 id="string-literals" tabindex="-1">String Literals <a class="header-anchor" href="#string-literals" aria-label="Permalink to &quot;String Literals&quot;">​</a></h2><h3 id="basic-strings" tabindex="-1">Basic Strings <a class="header-anchor" href="#basic-strings" aria-label="Permalink to &quot;Basic Strings&quot;">​</a></h3><p>Enclosed in double quotes. Vex strings are UTF-8 encoded.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let greeting = &quot;Hello, World!&quot;;</span></span>
<span class="line"><span>let path = &quot;C:\\\\Windows\\\\System32&quot;;</span></span></code></pre></div><h3 id="f-strings-interpolation" tabindex="-1">F-Strings (Interpolation) <a class="header-anchor" href="#f-strings-interpolation" aria-label="Permalink to &quot;F-Strings (Interpolation)&quot;">​</a></h3><p>Prefix with <code>f</code> to interpret <code>{expression}</code> inside the string.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let name = &quot;Vex&quot;;</span></span>
<span class="line"><span>let version = 1;</span></span>
<span class="line"><span>// Prints: &quot;Language: Vex, Version: 1&quot;</span></span>
<span class="line"><span>(f&quot;Language: {name}, Version: {version}&quot;);</span></span></code></pre></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>F-strings are compiled to efficient string concatenation code at compile time.</p></div><h2 id="byte-literals" tabindex="-1">Byte Literals <a class="header-anchor" href="#byte-literals" aria-label="Permalink to &quot;Byte Literals&quot;">​</a></h2><p>Vex treats bytes as <code>u8</code>. We do not have a dedicated <code>char</code> type or single-quote literals <code>&#39;a&#39;</code>.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let letter_a: u8 = 97;      // ASCII for &#39;a&#39;</span></span>
<span class="line"><span>let newline: u8 = 10;       // ASCII for &#39;\\n&#39;</span></span></code></pre></div><h2 id="real-world-usage" tabindex="-1">Real World Usage <a class="header-anchor" href="#real-world-usage" aria-label="Permalink to &quot;Real World Usage&quot;">​</a></h2><h3 id="defining-configuration-flags-bitmasks" tabindex="-1">Defining Configuration Flags (Bitmasks) <a class="header-anchor" href="#defining-configuration-flags-bitmasks" aria-label="Permalink to &quot;Defining Configuration Flags (Bitmasks)&quot;">​</a></h3><p>Binary literals are perfect for bitmasks.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Define explicit types for safety</span></span>
<span class="line"><span>const READ: u8    = 0b00000001; // 1</span></span>
<span class="line"><span>const WRITE: u8   = 0b00000010; // 2</span></span>
<span class="line"><span>const EXECUTE: u8 = 0b00000100; // 4</span></span>
<span class="line"><span></span></span>
<span class="line"><span>fn check_access(perms: u8) {</span></span>
<span class="line"><span>    if perms &amp; READ != 0 {</span></span>
<span class="line"><span>        (&quot;Readable&quot;);</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="high-precision-math" tabindex="-1">High-Precision Math <a class="header-anchor" href="#high-precision-math" aria-label="Permalink to &quot;High-Precision Math&quot;">​</a></h3><p>Using explicit suffixes to ensure 64-bit or 128-bit precision.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn calculate_distance() {</span></span>
<span class="line"><span>    // Force f64 literals to prevent accidental f32 constraint</span></span>
<span class="line"><span>    let x = 10.5f64; </span></span>
<span class="line"><span>    let y = 20.2f64;</span></span>
<span class="line"><span>    // ...</span></span>
<span class="line"><span>}</span></span></code></pre></div>`,52)])])}const u=a(i,[["render",l]]);export{g as __pageData,u as default};
